import{_ as a,o as t,c as o,a4 as r}from"./chunks/framework.BlZvSPPP.js";const u=JSON.parse('{"title":"Interface: EventLoop · ui","description":"","frontmatter":{"title":"Interface: EventLoop · ui"},"headers":[],"relativePath":"api/ui/interfaces/EventLoop.md","filePath":"api/ui/interfaces/EventLoop.md"}'),s={name:"api/ui/interfaces/EventLoop.md"};function n(i,e,d,c,l,h){return t(),o("div",null,[...e[0]||(e[0]=[r(`<p><a href="./../">@jsvision/ui</a> / EventLoop</p><h1 id="interface-eventloop" tabindex="-1">Interface: EventLoop <a class="header-anchor" href="#interface-eventloop" aria-label="Permalink to &quot;Interface: EventLoop&quot;">​</a></h1><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L109" target="_blank" rel="noreferrer">ui/src/event/types.ts:109</a></p><p>The event loop: a host-agnostic engine that owns a render root, routes input and commands, manages focus, commands, and modal windows, and paints exactly one coalesced frame per dispatch tick.</p><p>You drive it entirely through <code>dispatch()</code> (decoded input) and the imperative methods below — no terminal is required, which is what makes it testable and embeddable. To connect it to a real terminal, either wire the <code>on*</code>/<code>write*</code> sinks to a host yourself, or use <code>createApplication</code>, which does that wiring for you. Create one with <a href="./../functions/createEventLoop.html">createEventLoop</a>.</p><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to &quot;Properties&quot;">​</a></h2><h3 id="oncaret" tabindex="-1">onCaret? <a class="header-anchor" href="#oncaret" aria-label="Permalink to &quot;onCaret?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>onCaret?</strong>: (<code>cell</code>) =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L218" target="_blank" rel="noreferrer">ui/src/event/types.ts:218</a></p><p>Called right after <a href="#onframe">onFrame</a> at every frame with the focused view&#39;s absolute caret cell, or <code>null</code> when nothing is focused or the focused view wants no visible caret. Wire it to move the terminal&#39;s hardware cursor. It reads the persisted view origin, so the caret position stays correct even on a partial repaint that skips the focused view. <code>undefined</code> ⇒ no caret output.</p><h4 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="cell" tabindex="-1">cell <a class="header-anchor" href="#cell" aria-label="Permalink to &quot;cell&quot;">​</a></h5><p><a href="./Point.html"><code>Point</code></a> | <code>null</code></p><h4 id="returns" tabindex="-1">Returns <a class="header-anchor" href="#returns" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="onframe" tabindex="-1">onFrame? <a class="header-anchor" href="#onframe" aria-label="Permalink to &quot;onFrame?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>onFrame?</strong>: (<code>buffer</code>) =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L211" target="_blank" rel="noreferrer">ui/src/event/types.ts:211</a></p><p>Called with the composed buffer after every frame (each dispatch tick, resize, and mount) so a host can paint it. Set this to <code>host.render</code> (or your own writer) after the host exists; <code>createApplication</code> wires it for you. While unset, frames are still composed but not pushed — headless tests read <code>renderRoot.buffer()</code> directly.</p><h4 id="parameters-1" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-1" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="buffer" tabindex="-1">buffer <a class="header-anchor" href="#buffer" aria-label="Permalink to &quot;buffer&quot;">​</a></h5><p><code>ScreenBuffer</code></p><h4 id="returns-1" tabindex="-1">Returns <a class="header-anchor" href="#returns-1" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="onresize" tabindex="-1">onResize? <a class="header-anchor" href="#onresize" aria-label="Permalink to &quot;onResize?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>onResize?</strong>: (<code>size</code>) =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L225" target="_blank" rel="noreferrer">ui/src/event/types.ts:225</a></p><p>Called inside <a href="#resize">resize</a> after the reflow settles the new geometry, so a handler can re-anchor viewport-sized chrome against fresh bounds (the app uses it to re-fit maximized windows and re-anchor the open menu). The loop repaints once more afterward so the adjustment is visible. <code>undefined</code> ⇒ resize only reflows.</p><h4 id="parameters-2" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-2" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="size" tabindex="-1">size <a class="header-anchor" href="#size" aria-label="Permalink to &quot;size&quot;">​</a></h5><p><a href="./Size2D.html"><code>Size2D</code></a></p><h4 id="returns-2" tabindex="-1">Returns <a class="header-anchor" href="#returns-2" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="popuphost" tabindex="-1">popupHost? <a class="header-anchor" href="#popuphost" aria-label="Permalink to &quot;popupHost?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>popupHost?</strong>: <a href="./PopupHost.html"><code>PopupHost</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L243" target="_blank" rel="noreferrer">ui/src/event/types.ts:243</a></p><p>The host that anchored dropdown popups (menus, combo boxes, date/color pickers) mount into. <code>createApplication</code> wires it to the app&#39;s overlay + focus. <code>undefined</code> ⇒ no host, so opening a dropdown is a safe no-op; a standalone <code>Dialog</code> can supply its own.</p><hr><h3 id="renderroot" tabindex="-1">renderRoot <a class="header-anchor" href="#renderroot" aria-label="Permalink to &quot;renderRoot&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>renderRoot</strong>: <a href="./RenderRoot.html"><code>RenderRoot</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L111" target="_blank" rel="noreferrer">ui/src/event/types.ts:111</a></p><p>The render root the loop builds and owns — read <code>renderRoot.buffer()</code> to inspect the composed frame.</p><hr><h3 id="writeclipboard" tabindex="-1">writeClipboard? <a class="header-anchor" href="#writeclipboard" aria-label="Permalink to &quot;writeClipboard?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>writeClipboard?</strong>: (<code>seq</code>) =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L237" target="_blank" rel="noreferrer">ui/src/event/types.ts:237</a></p><p>Called with a ready-to-write terminal clipboard sequence when a control copies/cuts text (the loop encodes and sanitizes it for you). Wire it to your output stream. <code>undefined</code> ⇒ clipboard writes are dropped, so copy/cut is a safe no-op headlessly.</p><h4 id="parameters-3" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-3" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="seq" tabindex="-1">seq <a class="header-anchor" href="#seq" aria-label="Permalink to &quot;seq&quot;">​</a></h5><p><code>string</code></p><h4 id="returns-3" tabindex="-1">Returns <a class="header-anchor" href="#returns-3" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><h2 id="methods" tabindex="-1">Methods <a class="header-anchor" href="#methods" aria-label="Permalink to &quot;Methods&quot;">​</a></h2><h3 id="commandsversion" tabindex="-1">commandsVersion() <a class="header-anchor" href="#commandsversion" aria-label="Permalink to &quot;commandsVersion()&quot;">​</a></h3><blockquote><p><strong>commandsVersion</strong>(): <code>number</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L152" target="_blank" rel="noreferrer">ui/src/event/types.ts:152</a></p><p>A version counter that changes whenever any command&#39;s enablement changes via <a href="#enablecommand">enableCommand</a>. Read it inside a view&#39;s <code>bind</code> to repaint on greying — the shell&#39;s status line and menu bar do exactly this so a disabled command greys live with no manual invalidate.</p><h4 id="returns-4" tabindex="-1">Returns <a class="header-anchor" href="#returns-4" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>number</code></p><hr><h3 id="dispatch" tabindex="-1">dispatch() <a class="header-anchor" href="#dispatch" aria-label="Permalink to &quot;dispatch()&quot;">​</a></h3><blockquote><p><strong>dispatch</strong>(<code>event</code>): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L128" target="_blank" rel="noreferrer">ui/src/event/types.ts:128</a></p><p>Feed one decoded input event (key/mouse/wheel/paste) into the loop; it routes and repaints in one tick.</p><h4 id="parameters-4" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-4" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="event" tabindex="-1">event <a class="header-anchor" href="#event" aria-label="Permalink to &quot;event&quot;">​</a></h5><p><a href="./../type-aliases/AppEvent.html"><code>AppEvent</code></a></p><h4 id="returns-5" tabindex="-1">Returns <a class="header-anchor" href="#returns-5" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="emitcommand" tabindex="-1">emitCommand() <a class="header-anchor" href="#emitcommand" aria-label="Permalink to &quot;emitCommand()&quot;">​</a></h3><blockquote><p><strong>emitCommand</strong>(<code>command</code>, <code>arg?</code>): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L142" target="_blank" rel="noreferrer">ui/src/event/types.ts:142</a></p><p>Emit a command, routing it to any handler. Dropped silently if the command is disabled.</p><h4 id="parameters-5" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-5" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="command" tabindex="-1">command <a class="header-anchor" href="#command" aria-label="Permalink to &quot;command&quot;">​</a></h5><p><code>string</code></p><h5 id="arg" tabindex="-1">arg? <a class="header-anchor" href="#arg" aria-label="Permalink to &quot;arg?&quot;">​</a></h5><p><code>unknown</code></p><h4 id="returns-6" tabindex="-1">Returns <a class="header-anchor" href="#returns-6" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="enablecommand" tabindex="-1">enableCommand() <a class="header-anchor" href="#enablecommand" aria-label="Permalink to &quot;enableCommand()&quot;">​</a></h3><blockquote><p><strong>enableCommand</strong>(<code>command</code>, <code>on</code>): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L144" target="_blank" rel="noreferrer">ui/src/event/types.ts:144</a></p><p>Enable or disable a command. While disabled, <code>emitCommand</code> for it is dropped.</p><h4 id="parameters-6" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-6" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="command-1" tabindex="-1">command <a class="header-anchor" href="#command-1" aria-label="Permalink to &quot;command&quot;">​</a></h5><p><code>string</code></p><h5 id="on" tabindex="-1">on <a class="header-anchor" href="#on" aria-label="Permalink to &quot;on&quot;">​</a></h5><p><code>boolean</code></p><h4 id="returns-7" tabindex="-1">Returns <a class="header-anchor" href="#returns-7" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="endmodal" tabindex="-1">endModal() <a class="header-anchor" href="#endmodal" aria-label="Permalink to &quot;endModal()&quot;">​</a></h3><blockquote><p><strong>endModal</strong>&lt;<code>R</code>&gt;(<code>result</code>): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L159" target="_blank" rel="noreferrer">ui/src/event/types.ts:159</a></p><p>Close the top-most modal, restore the previously focused view, and resolve its <code>execView</code> promise with <code>result</code>.</p><h4 id="type-parameters" tabindex="-1">Type Parameters <a class="header-anchor" href="#type-parameters" aria-label="Permalink to &quot;Type Parameters&quot;">​</a></h4><h5 id="r" tabindex="-1">R <a class="header-anchor" href="#r" aria-label="Permalink to &quot;R&quot;">​</a></h5><p><code>R</code></p><h4 id="parameters-7" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-7" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="result" tabindex="-1">result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;result&quot;">​</a></h5><p><code>R</code></p><h4 id="returns-8" tabindex="-1">Returns <a class="header-anchor" href="#returns-8" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="execview" tabindex="-1">execView() <a class="header-anchor" href="#execview" aria-label="Permalink to &quot;execView()&quot;">​</a></h3><blockquote><p><strong>execView</strong>&lt;<code>R</code>&gt;(<code>view</code>): <code>Promise</code>&lt;<code>R</code>&gt;</p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L157" target="_blank" rel="noreferrer">ui/src/event/types.ts:157</a></p><p>Open <code>view</code> as a modal: input is captured to its subtree until it closes. Returns a promise that resolves with the value passed to <a href="#endmodal">endModal</a>. <code>await</code> it to run a dialog and read its result.</p><h4 id="type-parameters-1" tabindex="-1">Type Parameters <a class="header-anchor" href="#type-parameters-1" aria-label="Permalink to &quot;Type Parameters&quot;">​</a></h4><h5 id="r-1" tabindex="-1">R <a class="header-anchor" href="#r-1" aria-label="Permalink to &quot;R&quot;">​</a></h5><p><code>R</code></p><h4 id="parameters-8" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-8" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="view" tabindex="-1">view <a class="header-anchor" href="#view" aria-label="Permalink to &quot;view&quot;">​</a></h5><p><a href="./../classes/View.html"><code>View</code></a></p><h4 id="returns-9" tabindex="-1">Returns <a class="header-anchor" href="#returns-9" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>Promise</code>&lt;<code>R</code>&gt;</p><hr><h3 id="focusinto" tabindex="-1">focusInto() <a class="header-anchor" href="#focusinto" aria-label="Permalink to &quot;focusInto()&quot;">​</a></h3><blockquote><p><strong>focusInto</strong>(<code>view</code>): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L138" target="_blank" rel="noreferrer">ui/src/event/types.ts:138</a></p><p>Focus <strong>into</strong> a container: restore its last-focused child, or focus its first focusable descendant.</p><h4 id="parameters-9" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-9" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="view-1" tabindex="-1">view <a class="header-anchor" href="#view-1" aria-label="Permalink to &quot;view&quot;">​</a></h5><p><a href="./../classes/View.html"><code>View</code></a></p><h4 id="returns-10" tabindex="-1">Returns <a class="header-anchor" href="#returns-10" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="focusnext" tabindex="-1">focusNext() <a class="header-anchor" href="#focusnext" aria-label="Permalink to &quot;focusNext()&quot;">​</a></h3><blockquote><p><strong>focusNext</strong>(): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L132" target="_blank" rel="noreferrer">ui/src/event/types.ts:132</a></p><p>Move focus to the next focusable view in traversal order, wrapping at the end.</p><h4 id="returns-11" tabindex="-1">Returns <a class="header-anchor" href="#returns-11" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="focusprev" tabindex="-1">focusPrev() <a class="header-anchor" href="#focusprev" aria-label="Permalink to &quot;focusPrev()&quot;">​</a></h3><blockquote><p><strong>focusPrev</strong>(): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L134" target="_blank" rel="noreferrer">ui/src/event/types.ts:134</a></p><p>Move focus to the previous focusable view in traversal order, wrapping at the start.</p><h4 id="returns-12" tabindex="-1">Returns <a class="header-anchor" href="#returns-12" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="focusview" tabindex="-1">focusView() <a class="header-anchor" href="#focusview" aria-label="Permalink to &quot;focusView()&quot;">​</a></h3><blockquote><p><strong>focusView</strong>(<code>view</code>): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L136" target="_blank" rel="noreferrer">ui/src/event/types.ts:136</a></p><p>Focus exactly <code>view</code>. A no-op if <code>view</code> is not currently focusable.</p><h4 id="parameters-10" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-10" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="view-2" tabindex="-1">view <a class="header-anchor" href="#view-2" aria-label="Permalink to &quot;view&quot;">​</a></h5><p><a href="./../classes/View.html"><code>View</code></a></p><h4 id="returns-13" tabindex="-1">Returns <a class="header-anchor" href="#returns-13" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="getfocused" tabindex="-1">getFocused() <a class="header-anchor" href="#getfocused" aria-label="Permalink to &quot;getFocused()&quot;">​</a></h3><blockquote><p><strong>getFocused</strong>(): <a href="./../classes/View.html"><code>View</code></a> | <code>null</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L140" target="_blank" rel="noreferrer">ui/src/event/types.ts:140</a></p><p>The currently focused view, or <code>null</code> if nothing is focused.</p><h4 id="returns-14" tabindex="-1">Returns <a class="header-anchor" href="#returns-14" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><a href="./../classes/View.html"><code>View</code></a> | <code>null</code></p><hr><h3 id="iscommandenabled" tabindex="-1">isCommandEnabled() <a class="header-anchor" href="#iscommandenabled" aria-label="Permalink to &quot;isCommandEnabled()&quot;">​</a></h3><blockquote><p><strong>isCommandEnabled</strong>(<code>command</code>): <code>boolean</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L146" target="_blank" rel="noreferrer">ui/src/event/types.ts:146</a></p><p>Whether a command is currently enabled. Commands are enabled by default until disabled.</p><h4 id="parameters-11" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-11" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="command-2" tabindex="-1">command <a class="header-anchor" href="#command-2" aria-label="Permalink to &quot;command&quot;">​</a></h5><p><code>string</code></p><h4 id="returns-15" tabindex="-1">Returns <a class="header-anchor" href="#returns-15" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>boolean</code></p><hr><h3 id="mount" tabindex="-1">mount() <a class="header-anchor" href="#mount" aria-label="Permalink to &quot;mount()&quot;">​</a></h3><blockquote><p><strong>mount</strong>(<code>root</code>): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L113" target="_blank" rel="noreferrer">ui/src/event/types.ts:113</a></p><p>Mount a view tree as the loop&#39;s root and paint the first frame. Call once before dispatching.</p><h4 id="parameters-12" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-12" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="root" tabindex="-1">root <a class="header-anchor" href="#root" aria-label="Permalink to &quot;root&quot;">​</a></h5><p><a href="./../classes/View.html"><code>View</code></a></p><h4 id="returns-16" tabindex="-1">Returns <a class="header-anchor" href="#returns-16" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="oncommand" tabindex="-1">onCommand() <a class="header-anchor" href="#oncommand" aria-label="Permalink to &quot;onCommand()&quot;">​</a></h3><blockquote><p><strong>onCommand</strong>(<code>command</code>, <code>handler</code>): () =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L192" target="_blank" rel="noreferrer">ui/src/event/types.ts:192</a></p><p>Register a handler for a named command; returns a function that unregisters it. Every handler registered for a command runs (in registration order) when that command is emitted, and a handled command is consumed there — a downstream view matching the same command does not also receive it.</p><p>Handlers run in the pre-process phase, so an <code>onCommand</code> handler fires before a focused view could handle the same command. One exception: while a modal (e.g. a <code>Dialog</code>) owns the dispatch scope, commands are confined to the modal subtree, so a general <code>onCommand</code> handler does not fire until the modal closes.</p><h4 id="parameters-13" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-13" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="command-3" tabindex="-1">command <a class="header-anchor" href="#command-3" aria-label="Permalink to &quot;command&quot;">​</a></h5><p><code>string</code></p><p>The command name to handle.</p><h5 id="handler" tabindex="-1">handler <a class="header-anchor" href="#handler" aria-label="Permalink to &quot;handler&quot;">​</a></h5><p>() =&gt; <code>void</code></p><p>Called when the command is emitted.</p><h4 id="returns-17" tabindex="-1">Returns <a class="header-anchor" href="#returns-17" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p>A function that unregisters this handler (idempotent).</p><p>() =&gt; <code>void</code></p><hr><h3 id="refreshcaret" tabindex="-1">refreshCaret() <a class="header-anchor" href="#refreshcaret" aria-label="Permalink to &quot;refreshCaret()&quot;">​</a></h3><blockquote><p><strong>refreshCaret</strong>(): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L231" target="_blank" rel="noreferrer">ui/src/event/types.ts:231</a></p><p>Re-send the current caret cell to <a href="#oncaret">onCaret</a> out of band. <code>run()</code> calls it once after the first frame (which is painted directly, not through a tick) to position the initial cursor. A no-op when <code>onCaret</code> is unset.</p><h4 id="returns-18" tabindex="-1">Returns <a class="header-anchor" href="#returns-18" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="releasecapture" tabindex="-1">releaseCapture() <a class="header-anchor" href="#releasecapture" aria-label="Permalink to &quot;releaseCapture()&quot;">​</a></h3><blockquote><p><strong>releaseCapture</strong>(): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L204" target="_blank" rel="noreferrer">ui/src/event/types.ts:204</a></p><p>Release the pointer capture. A no-op if nothing is captured.</p><h4 id="returns-19" tabindex="-1">Returns <a class="header-anchor" href="#returns-19" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="resize" tabindex="-1">resize() <a class="header-anchor" href="#resize" aria-label="Permalink to &quot;resize()&quot;">​</a></h3><blockquote><p><strong>resize</strong>(<code>size</code>): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L130" target="_blank" rel="noreferrer">ui/src/event/types.ts:130</a></p><p>Resize the viewport: reflow the tree and paint exactly one frame.</p><h4 id="parameters-14" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-14" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="size-1" tabindex="-1">size <a class="header-anchor" href="#size-1" aria-label="Permalink to &quot;size&quot;">​</a></h5><p><a href="./Size2D.html"><code>Size2D</code></a></p><h4 id="returns-20" tabindex="-1">Returns <a class="header-anchor" href="#returns-20" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="setacceleratormode" tabindex="-1">setAcceleratorMode() <a class="header-anchor" href="#setacceleratormode" aria-label="Permalink to &quot;setAcceleratorMode()&quot;">​</a></h3><blockquote><p><strong>setAcceleratorMode</strong>(<code>on</code>): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L166" target="_blank" rel="noreferrer">ui/src/event/types.ts:166</a></p><p>Turn accelerator mode on or off. When on, every reachable <code>~X~</code> hotkey is underlined and a bare letter fires the matching accelerator like <code>Alt</code>+letter. The reveal key (default <code>F12</code>) toggles this for you; call it directly to arm/dismiss the mode programmatically. A no-op when the feature is disabled (<code>revealKey: null</code>).</p><h4 id="parameters-15" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-15" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="on-1" tabindex="-1">on <a class="header-anchor" href="#on-1" aria-label="Permalink to &quot;on&quot;">​</a></h5><p><code>boolean</code></p><h4 id="returns-21" tabindex="-1">Returns <a class="header-anchor" href="#returns-21" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="setcapture" tabindex="-1">setCapture() <a class="header-anchor" href="#setcapture" aria-label="Permalink to &quot;setCapture()&quot;">​</a></h3><blockquote><p><strong>setCapture</strong>(<code>view</code>): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L202" target="_blank" rel="noreferrer">ui/src/event/types.ts:202</a></p><p>Capture the pointer to <code>view</code>: while captured, <strong>all</strong> mouse/wheel events go to <code>view</code> (with view-local <code>ev.local</code> coordinates), bypassing hit-testing and focus-on-click — this is how a drag or resize keeps tracking even after the cursor leaves the affordance. Setting a new target replaces any current one; capture is released automatically when a modal opens/closes or the target unmounts.</p><h4 id="parameters-16" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-16" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="view-3" tabindex="-1">view <a class="header-anchor" href="#view-3" aria-label="Permalink to &quot;view&quot;">​</a></h5><p><a href="./../classes/View.html"><code>View</code></a></p><h4 id="returns-22" tabindex="-1">Returns <a class="header-anchor" href="#returns-22" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="settheme" tabindex="-1">setTheme() <a class="header-anchor" href="#settheme" aria-label="Permalink to &quot;setTheme()&quot;">​</a></h3><blockquote><p><strong>setTheme</strong>(<code>theme</code>): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L177" target="_blank" rel="noreferrer">ui/src/event/types.ts:177</a></p><p>Replace the active theme and repaint every view with the new colors in one coalesced frame. Safe to call from anywhere — a command handler, an async callback, or a bare imperative call between input ticks — because the swap runs inside the loop&#39;s own tick and reuses its trailing flush + <code>onFrame</code>, so the repainted frame reaches the host even outside a dispatch.</p><h4 id="parameters-17" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-17" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="theme" tabindex="-1">theme <a class="header-anchor" href="#theme" aria-label="Permalink to &quot;theme&quot;">​</a></h5><p><code>Theme</code></p><p>The theme to switch to.</p><h4 id="returns-23" tabindex="-1">Returns <a class="header-anchor" href="#returns-23" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><h4 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h4><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">loop.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setTheme</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(nordTheme); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// repaints immediately, from any call context</span></span></code></pre></div><hr><h3 id="stop" tabindex="-1">stop() <a class="header-anchor" href="#stop" aria-label="Permalink to &quot;stop()&quot;">​</a></h3><blockquote><p><strong>stop</strong>(): <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75326e6b0cbb976c51c5032bbf03512137ffa5b0/packages/ui/src/event/types.ts#L126" target="_blank" rel="noreferrer">ui/src/event/types.ts:126</a></p><p>Stop the loop&#39;s out-of-tick painter. After <code>stop()</code>, a mutation that would normally schedule a deferred repaint — a timer, a promise continuation, a direct call between ticks — is ignored, and any already-queued deferred paint is skipped, so a late callback during or after teardown never writes to a stopped host. Idempotent. In-tick painting (a <code>dispatch</code>/<code>resize</code>/command) is unaffected: a running loop never calls this, and <code>run()</code> calls it once during shutdown. It does not dispose the mounted view tree.</p><h4 id="returns-24" tabindex="-1">Returns <a class="header-anchor" href="#returns-24" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><h4 id="example-1" tabindex="-1">Example <a class="header-anchor" href="#example-1" aria-label="Permalink to &quot;Example&quot;">​</a></h4><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Inside run()&#39;s shutdown, after the terminal is restored:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">loop.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">stop</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// gate the deferred painter before detaching the frame/caret sinks</span></span></code></pre></div>`,265)])])}const b=a(s,[["render",n]]);export{u as __pageData,b as default};
